import json, re

# Load data from stored results
funding_path = locals()['var_functions.query_db:12']
civic_path = locals()['var_functions.query_db:2']

with open(funding_path, 'r') as f:
    funding_records = json.load(f)

with open(civic_path, 'r') as f:
    civic_docs = json.load(f)

# Build project funding lookup
funding_lookup = {record['Project_Name']: int(record['Amount']) for record in funding_records}

# Find Spring 2022 projects
spring_projects = set()

for doc in civic_docs:
    text = doc['text'].replace('•', '')
    lines = text.split('\n')

    for i in range(len(lines)):
        line = lines[i].strip()
        if 'Spring 2022' in line or '2022-Spring' in line:
            # Search backwards for project name
            for j in range(i-1, max(0, i-5), -1):
                prev = lines[j].strip().replace('•', '')
                if prev and 5 < len(prev) < 100:
                    keywords = ['project', 'improvements', 'repairs', 'construction', 'installation', 'upgrades']
                    if any(k in prev.lower() for k in keywords):
                        spring_projects.add(prev)
                        break

# Match with funding data
matched = {}
for proj in spring_projects:
    if proj in funding_lookup:
        matched[proj] = funding_lookup[proj]
    else:
        for fund_proj, amount in funding_lookup.items():
            if proj.lower() in fund_proj.lower() or fund_proj.lower().split('(')[0].strip() == proj.lower():
                matched[fund_proj] = amount
                break

# Calculate totals
total_projects = len(matched)
total_funding = sum(matched.values())

# Prepare output
result = {
    'total_projects': total_projects,
    'total_funding': total_funding,
    'projects': [{'name': proj, 'amount': amount} for proj, amount in matched.items()]
}

print('__RESULT__:')
print(json.dumps(result))

